+static jl_cgval_t emit_memorynew(jl_codectx_t &ctx, jl_datatype_t *typ, jl_cgval_t nel, jl_genericmemory_t *inst)
+{
+    emit_typecheck(ctx, nel, (jl_value_t*)jl_long_type, "memorynew");
+    nel = update_julia_type(ctx, nel, (jl_value_t*)jl_long_type);
+    if (nel.typ == jl_bottom_type)
+        return jl_cgval_t();
+
+    const jl_datatype_layout_t *layout = ((jl_datatype_t*)typ)->layout;
+    assert(((jl_datatype_t*)typ)->has_concrete_subtype && layout != NULL);
+    size_t elsz = layout->size;
+    int isboxed = layout->flags.arrayelem_isboxed;
+    int isunion = layout->flags.arrayelem_isunion;
+    int zi = ((jl_datatype_t*)typ)->zeroinit;
+    if (isboxed)
+        elsz = sizeof(void*);
+
+    auto ptls = get_current_ptls(ctx);
+    auto T_size = ctx.types().T_size;
+    auto int8t = getInt8Ty(ctx.builder.getContext());
+    BasicBlock *emptymemBB, *nonemptymemBB, *retvalBB;
+    emptymemBB = BasicBlock::Create(ctx.builder.getContext(), "emptymem");
+    nonemptymemBB = BasicBlock::Create(ctx.builder.getContext(), "nonemptymem");
+    retvalBB = BasicBlock::Create(ctx.builder.getContext(), "retval");
+    auto nel_unboxed = emit_unbox(ctx, ctx.types().T_size, nel, (jl_value_t*)jl_long_type);
+    Value *memorynew_empty = ctx.builder.CreateICmpEQ(nel_unboxed, ConstantInt::get(T_size, 0));
+    setName(ctx.emission_context, memorynew_empty, "memorynew_empty");
+    ctx.builder.CreateCondBr(memorynew_empty, emptymemBB, nonemptymemBB);
+    // if nel == 0
+    emptymemBB->insertInto(ctx.f);
+    ctx.builder.SetInsertPoint(emptymemBB);
+    auto emptyalloc = track_pjlvalue(ctx, literal_pointer_val(ctx, (jl_value_t*)inst));
+    ctx.builder.CreateBr(retvalBB);
+    nonemptymemBB->insertInto(ctx.f);
+    ctx.builder.SetInsertPoint(nonemptymemBB);
+    // else actually allocate mem
+    auto arg_typename = [&] JL_NOTSAFEPOINT {
+        std::string type_str;
+        auto eltype = jl_tparam1(typ);
+        if (jl_is_datatype(eltype))
+            type_str = jl_symbol_name(((jl_datatype_t*)eltype)->name->name);
+        else if (jl_is_uniontype(eltype))
+            type_str = "Union";
+        else
+            type_str = "<unknown type>";
+        return "Memory{" + type_str + "}[]";","path":"src/cgutils.cpp","commit_id":"40e1d6bf26a5acbc58c5e0762a0cbae24b4f45d9","original_commit_id":"40e1d6bf26a5acbc58c5e0762a0cbae24b4f45d9","user":{"login":"topolarity","id":84105208,"node_id":"MDQ6VXNlcjg0MTA1MjA4","avatar_url":"https://avatars.githubusercontent.com/u/84105208?v=4","gravatar_id":"","url":"https://api.github.com/users/topolarity","html_url":"https://github.com/topolarity","followers_url":"https://api.github.com/users/topolarity/followers","following_url":"https://api.github.com/users/topolarity/following{/other_user}","gists_url":"https://api.github.com/users/topolarity/gists{/gist_id}","starred_url":"https://api.github.com/users/topolarity/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/topolarity/subscriptions","organizations_url":"https://api.github.com/users/topolarity/orgs","repos_url":"https://api.github.com/users/topolarity/repos","events_url":"https://api.github.com/users/topolarity/events{/privacy}","received_events_url":"https://api.github.com/users/topolarity/received_events","type":"User","user_view_type":"public","site_admin":false},"body":"Minor nit, but this code feels like it ought to live somewhere else","created_at":"2024-12-03T01:11:40Z","updated_at":"2024-12-03T01:35:57Z","html_url":"https://github.com/JuliaLang/julia/pull/55913#discussion_r1866840491","pull_request_url":"https://api.github.com/repos/JuliaLang/julia/pulls/55913","author_association":"MEMBER","_links":{"self":{"href":"https://api.github.com/repos/JuliaLang/julia/pulls/comments/1866840491"},"html":{"href":"https://github.com/JuliaLang/julia/pull/55913#discussion_r1866840491"},"pull_request":{"href":"https://api.github.com/repos/JuliaLang/julia/pulls/55913"}},"reactions":{"url":"https://api.github.com/repos/JuliaLang/julia/pulls/comments/1866840491/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"start_line":null,"original_start_line":null,"start_side":null,"line":4635,"original_line":4635,"side":"RIGHT","original_position":167,"position":167,"subject_type":"line"},"pull_request":{"url":"https://api.github.com/repos/JuliaLang/julia/pulls/55913","id":2096812185,"node_id":"PR_kwDOABkWpM58-tCZ","html_url":"https://github.com/JuliaLang/julia/pull/55913","diff_url":"https://github.com/JuliaLang/julia/pull/55913.diff","patch_url":"https://github.com/JuliaLang/julia/pull/55913.patch","issue_url":"https://api.github.com/repos/JuliaLang/julia/issues/55913","number":55913,"state":"open","locked":false,"title":"make `memorynew` intrinsic","user":{"login":"oscardssmith","id":11729272,"node_id":"MDQ6VXNlcjExNzI5Mjcy","avatar_url":"https://avatars.githubusercontent.com/u/11729272?v=4","gravatar_id":"","url":"https://api.github.com/users/oscardssmith","html_url":"https://github.com/oscardssmith","followers_url":"https://api.github.com/users/oscardssmith/followers","following_url":"https://api.github.com/users/oscardssmith/following{/other_user}","gists_url":"https://api.github.com/users/oscardssmith/gists{/gist_id}","starred_url":"https://api.github.com/users/oscardssmith/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/oscardssmith/subscriptions","organizations_url":"https://api.github.com/users/oscardssmith/orgs","repos_url":"https://api.github.com/users/oscardssmith/repos","events_url":"https://api.github.com/users/oscardssmith/events{/privacy}","received_events_url":"https://api.github.com/users/oscardssmith/received_events","type":"User","user_view_type":"public","site_admin":false},"body":"This speeds up making new `Memory`s and allow the compiler to better understand what's going on, allowing for LLVM level escape analysis in some cases. There is more room to grow this (currently this only optimizes for fairly small `Memory` since bigger ones would require writing some more LLVM code, and we probably want a size limit on putting `Memory` on the stack to avoid stackoverflow. For larger ones, we could potentially inline the `free` so the `Memory` doesn't have to be swept by the GC, etc. 

Benchmarks:
```
julia> f(T) = Memory{T}(undef, 2);

julia> @btime f(Int);
  7.879 ns (1 allocation: 48 bytes) #before
  3.959 ns (1 allocation: 48 bytes) #after 

julia> @btime f(Union{Int, Nothing})
  8.426 ns (1 allocation: 48 bytes) #before
  4.017 ns (1 allocation: 48 bytes) #after 

julia> @btime f(Any);
  8.637 ns (1 allocation: 48 bytes) #before
  3.920 ns (1 allocation: 48 bytes) #after 

julia> function g()
           m = Memory{Int}(undef, 2)
           for i in 1:2
              m[i] = i
           end
           m[1]+m[2]
       end

julia> @btime g()
  9.735 ns (1 allocation: 48 bytes) #before
  1.719 ns (0 allocations: 0 bytes) #after
```
