julia> @eval Base function foo()
           @_noub_if_noinbounds_meta
           bar()
       end;

julia> @eval Base @inline function bar()
           @_noub_if_noinbounds_meta
           Core.compilerbarrier(:type, Returns(nothing))()
       end;

julia> Base.infer_effects(Base.foo, ())
(!c,!e,!n,!t,!s,!m,+u,!o,!r)

julia> Base.infer_effects(Base.bar, ())
(!c,!e,!n,!t,!s,!m,?u,!o,!r)
```

